CREATE DATABASE /*!32312 IF NOT EXISTS*/ `medth` /*!40100 DEFAULT CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci */;

USE `medth`;
DROP TABLE IF EXISTS `bookings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `bookings` (
  `id` bigint(20) unsigned NOT NULL AUTO_INCREMENT,
  `branch_id` int(10) unsigned NOT NULL,
  `booking_code` varchar(30) NOT NULL,
  `customer_name` varchar(150) NOT NULL,
  `customer_phone` varchar(20) NOT NULL,
  `line_id` varchar(100) DEFAULT NULL,
  `booking_date` date NOT NULL,
  `time_slot_id` int(10) unsigned NOT NULL,
  `staff_id` int(10) unsigned NOT NULL,
  `notes` text DEFAULT NULL,
  `booking_status` enum('pending','confirmed','completed') NOT NULL DEFAULT 'pending',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0,
  `delete_by` varchar(150) DEFAULT NULL,
  `delete_date_time` datetime DEFAULT NULL,
  `delete_note` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_bookings_branch_code` (`branch_id`,`booking_code`),
  KEY `idx_bookings_branch` (`branch_id`),
  KEY `idx_bookings_branch_date` (`branch_id`,`booking_date`),
  KEY `idx_bookings_staff_branch` (`staff_id`,`branch_id`),
  KEY `idx_bookings_branch_slot` (`branch_id`,`time_slot_id`)
) ENGINE=InnoDB AUTO_INCREMENT=344 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

